@import url("https://fonts.googleapis.com/css2?family=Bebas+Neue&display=swap");

:root {
  --background: light-dark(
    oklch(100% 0.00011 271.152),
    oklch(18.22% 0.00002 271.152)
  );
  --foreground: light-dark(
    oklch(18.22% 0.00002 271.152),
    oklch(98.511% 0.00011 271.152)
  );
}

html {
  color-scheme: light dark;
}

body {
  margin: 0;
  padding: 0;
  height: 100vh;
  width: 100%;
  background: var(--background);
  display: flex;
  align-items: center;
  justify-content: center;
}

.hacker-text {
  font-family: "Bebas Neue", sans-serif;
  text-transform: uppercase;
  font-size: 4rem;
  cursor: pointer;
  color: var(--foreground);
}

document.addEventListener("DOMContentLoaded", () => {
  const textElements = document.querySelectorAll(".hacker-text");
  const letters = "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  let interval = null;
  let timeout = null;

  const scrambleText = (target) => {
    let iteration = 0;

    clearInterval(interval);

    interval = setInterval(() => {
      if (!target.dataset.value) return;

      target.innerText = target.innerText
        .split("")
        .map((letter, index) => {
          if (index < iteration) {
            return target.dataset.value[index];
          }
          return letters[Math.floor(Math.random() * 26)];
        })
        .join("");

      if (iteration >= target.dataset.value.length) {
        clearInterval(interval);
      }

      iteration += 1 / 3;
    }, 30);
  };

  const applyEffect = () => {
    if (window.matchMedia("(min-width: 768px)").matches) {
      textElements.forEach((textElement) => {
        textElement.addEventListener("mouseover", (event) => {
          const target = event.target;
          scrambleText(target);
        });
      });
    }
    // Run effect on page load after 600ms for all devices
    timeout = setTimeout(() => {
      textElements.forEach((textElement) => {
        scrambleText(textElement);
      });
    }, 600);
  };

  applyEffect();

  window.addEventListener("beforeunload", () => {
    if (interval) clearInterval(interval);
    if (timeout) clearTimeout(timeout);
  });
});
